import type { ScaleLinear, ScaleLogarithmic, ScaleSymLog } from 'd3-scale';

import { getThresholdPixel } from './get-threshold-pixel.ts.js';

/**
 * Converts a domain value to its pixel position for a ThresholdBar marker.
 * Infinite values are preserved as-is so the ThresholdBar can sort and group markers correctly.
 * Finite values are converted to pixel coordinates using the provided scale and layout.
 * @param value - domain value (can be Infinity/-Infinity for unbounded thresholds)
 * @param scale - axis scale
 * @param layout - chart orientation
 * @returns pixel position, or Infinity/-Infinity for unbounded values
 */
export function getMarkerPixel(
  value: number,
  scale:
    | ScaleLinear<number, number>
    | ScaleLogarithmic<number, number>
    | ScaleSymLog<number, number>,
  layout: 'vertical' | 'horizontal',
): number {
  if (!isFinite(value)) {
    return layout === 'vertical' ? -value : value;
  }

  return getThresholdPixel(value, scale, layout);
}
